def assess(record: dict) -> str:
    required = {"case_id", "depth", "metric", "params", "rerun_metric", "seed", "tolerance"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = abs(record["metric"] - record["rerun_metric"]) <= record["tolerance"]
    return "PASS" if ok else "MARK_RUN_NONREPRODUCIBLE"

